    "public char[] expandCurrentSegment()
    {
        final char[] curr = _currentSegment;
        final int len = curr.length;
        // Grow by 50% by default; once at or above the maximum threshold, grow more slowly by 25%
        final int newLen = (len >= MAX_SEGMENT_LEN)
                ? (len + (len >> 2))
                : Math.min(MAX_SEGMENT_LEN, len + (len >> 1));
        return (_currentSegment = java.util.Arrays.copyOf(curr, newLen));
    }"
  ],
  "additional_testcases": [
    {
      "path": "com/fasterxml/jackson/core/util/TestTextBuffer.java",
      "testcase": "public void testExpandNoUnitGrowthAtThreshold()
      {
          TextBuffer tb = new TextBuffer(new BufferRecycler());
          char[] buf = tb.getCurrentSegment();

          // Expand enough times to cross any reasonable threshold
          // and ensure we never get just +1 growth at boundary
          for (int i = 0; i < 200000; ++i) {
              char[] old = buf;
              buf = tb.expandCurrentSegment();
              if (buf.length == old.length + 1) {
                  fail("Unexpected unit-size growth at boundary: " + old.length + " -> " + buf.length);
              }
              if (buf.length > 5_000_000) {
                  break;
              }
          }
      }"
    }
  ]
}

