        // Most likely, object:
        if (_type == TYPE_OBJECT) {
            // Can not write a value in object context without a preceding field name
            if (!_gotName) {
                return STATUS_EXPECT_NAME;
            }
            _gotName = false;
            ++_index;
            return STATUS_OK_AFTER_COLON;
